 97→	s.log.InfoContext(r.Context(), "health check")
 98→	w.Header().Set("Content-Type", "application/json")
 99→	fmt.Fprintf(w, `{"status":"ok","service":"aileron","version":"0.1.0","timestamp":"%s"}`, time.Now().UTC().Format(time.RFC3339))
100→}
