11→func apiURL() string {
12→	if u := os.Getenv("AILERON_API_URL"); u != "" {
13→		return u
14→	}
15→	return "http://localhost:8080"
16→}
17→
18→func TestHealthEndpoint(t *testing.T) {
19→	resp, err := http.Get(apiURL() + "/v1/health")
20→	if err != nil {
21→		t.Fatalf("health request failed: %v", err)
22→	}
23→	defer resp.Body.Close()
24→	if resp.StatusCode != http.StatusOK {
25→		t.Fatalf("expected 200, got %d", resp.StatusCode)
26→	}
27→	validateResponse(t, resp)
28→}
