  1→// Package main is the entry point for the Aileron control plane server.
  2→//
  3→// The server wires together the core components — policy engine, approval
  4→// orchestrator, connector registry, vault, notifiers, and audit store —
  5→// and exposes the control plane API over HTTP.
  6→package main
  7→
  8→import (
  9→	"context"
 10→	"encoding/json"
 11→	"fmt"
 12→	"log/slog"
 13→	"net/http"
 14→	"os"
 15→	"os/signal"
 16→	"syscall"
 17→	"time"
 18→
 19→	api "github.com/ALRubinger/aileron/core/api/gen"
 20→	"github.com/ALRubinger/aileron/core/connector"
 21→	googlecalendar "github.com/ALRubinger/aileron/core/connector/calendar/google"
 22→	"github.com/ALRubinger/aileron/core/connector/git/github"
 23→	"github.com/ALRubinger/aileron/core/connector/payments/stripe"
 24→)
 25→
 26→func main() {
 27→	log := slog.New(slog.NewJSONHandler(os.Stdout, nil))
 28→
 29→	if err := run(log); err != nil {
 30→		log.Error("server exited with error", "error", err)
 31→		os.Exit(1)
 32→	}
 33→}
 34→
 35→func run(log *slog.Logger) error {
 36→	ctx := context.Background()
 37→	cfg := configFromEnv()
 38→
 39→	// --- Connector registry ---
 40→	registry := connector.NewRegistry()
 41→	registry.Register(ctx, stripe.New())
 42→	registry.Register(ctx, googlecalendar.New())
 43→	registry.Register(ctx, github.New())
 44→
 45→	// --- HTTP server ---
 46→	mux := http.NewServeMux()
 47→
 48→	// Register generated API routes from the OpenAPI spec.
 49→	server := &apiServer{log: log, registry: registry}
 50→	api.HandlerFromMux(server, mux)
 51→
 52→	// Register non-spec routes (docs, raw spec).
 53→	registerDocsRoutes(mux)
 54→
 55→	// Middleware chain: CORS → request ID → logging → routes.
 56→	var handler http.Handler = mux
 57→	handler = loggingMiddleware(log, handler)
 58→	handler = requestIDMiddleware(handler)
 59→	handler = corsMiddleware(handler)
 60→
 61→	srv := &http.Server{
 62→		Addr:         cfg.addr,
 63→		Handler:      handler,
 64→		ReadTimeout:  10 * time.Second,
 65→		WriteTimeout: 30 * time.Second,
 66→		IdleTimeout:  120 * time.Second,
 67→	}
 68→
 69→	// Graceful shutdown on SIGINT / SIGTERM.
 70→	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
 71→	defer stop()
 72→
 73→	go func() {
 74→		log.Info("server listening", "addr", cfg.addr)
 75→		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
 76→			log.Error("listen error", "error", err)
 77→		}
 78→	}()
 79→
 80→	<-ctx.Done()
 81→	log.Info("shutting down")
 82→
 83→	shutdownCtx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
 84→	defer cancel()
 85→
 86→	return srv.Shutdown(shutdownCtx)
 87→}
