 1→// Package notify defines the SPI for human approval notifications.
 2→//
 3→// When an intent requires human approval, the approval orchestrator
 4→// dispatches a notification via this SPI. The notification includes a
 5→// deep link back to the web app where the approver can review and act.
 6→//
 7→// The built-in implementations deliver via Slack and email. Alternative
 8→// implementations can target other channels (PagerDuty, SMS, Teams, etc.)
 9→// without modifying the orchestrator.
10→package notify
11→
12→import "context"
13→
14→// Notifier delivers approval request notifications to human approvers.
15→type Notifier interface {
16→	// Notify sends an approval request notification to the listed approvers.
17→	Notify(ctx context.Context, n Notification) error
18→}
19→
20→// Notification is the data delivered to approvers when an approval is needed.
21→type Notification struct {
22→	ApprovalID  string
23→	IntentID    string
24→	WorkspaceID string
25→	// Summary is a one-line human-readable description of what the agent
26→	// wants to do, drawn from the intent.
27→	Summary string
28→	// ReviewURL is the deep link to the approval UI for this request.
29→	ReviewURL string
30→	// Approvers are the people who should receive this notification.
31→	Approvers []Approver
32→}
33→
34→// Approver is a person who should be notified about an approval request.
35→type Approver struct {
36→	PrincipalID string
37→	DisplayName string
38→	// Contact is the channel-specific address (email address, Slack user ID).
39→	Contact string
40→}
41→
42→// Multi dispatches a notification to multiple notifiers in sequence.
43→// Errors from individual notifiers are collected but do not stop delivery
44→// to subsequent notifiers.
45→type Multi struct {
46→	notifiers []Notifier
47→}
48→
49→// NewMulti returns a Notifier that dispatches to all provided notifiers.
50→func NewMulti(notifiers ...Notifier) *Multi {
51→	return &Multi{notifiers: notifiers}
52→}
53→
54→// Notify dispatches the notification to all registered notifiers.
55→func (m *Multi) Notify(ctx context.Context, n Notification) error {
56→	var errs []error
57→	for _, notifier := range m.notifiers {
58→		if err := notifier.Notify(ctx, n); err != nil {
59→			errs = append(errs, err)
60→		}
61→	}
62→	if len(errs) > 0 {
63→		return &MultiError{Errors: errs}
64→	}
65→	return nil
66→}
67→
68→// MultiError collects errors from multiple notifiers.
69→type MultiError struct {
70→	Errors []error
71→}
72→
73→func (e *MultiError) Error() string {
74→	msg := "notification errors:"
75→	for _, err := range e.Errors {
76→		msg += " " + err.Error() + ";"
77→	}
78→	return msg
79→}
80→

 1→// Package aileron provides a Go client for the Aileron control plane API.
 2→//
 3→// Usage:
 4→//
 5→//	client := aileron.NewClient("https://api.example.com", aileron.WithAPIKey("..."))
 6→//	intent, err := client.Intents.Create(ctx, aileron.CreateIntentRequest{ ... })
 7→package aileron
 8→
 9→import (
10→	"net/http"
11→	"time"
12→)
13→
14→// Client is the Aileron API client.
15→type Client struct {
16→	baseURL    string
17→	httpClient *http.Client
18→	apiKey     string
19→
20→	Intents  *IntentsService
21→	Approvals *ApprovalsService
22→	Policies *PoliciesService
23→}
24→
25→// Option configures the client.
26→type Option func(*Client)
27→
28→// WithAPIKey sets the API key for authentication.
29→func WithAPIKey(key string) Option {
30→	return func(c *Client) {
31→		c.apiKey = key
32→	}
33→}
34→
35→// WithHTTPClient sets a custom HTTP client.
36→func WithHTTPClient(hc *http.Client) Option {
37→	return func(c *Client) {
38→		c.httpClient = hc
39→	}
40→}
41→
42→// NewClient returns a new Aileron API client.
43→func NewClient(baseURL string, opts ...Option) *Client {
44→	c := &Client{
45→		baseURL: baseURL,
46→		httpClient: &http.Client{
47→			Timeout: 30 * time.Second,
48→		},
49→	}
50→	for _, opt := range opts {
51→		opt(c)
52→	}
53→
54→	c.Intents = &IntentsService{client: c}
55→	c.Approvals = &ApprovalsService{client: c}
56→	c.Policies = &PoliciesService{client: c}
57→
58→	return c
59→}
60→
61→// IntentsService provides access to intent endpoints.
62→// TODO: implement Create, Get, List, AppendEvidence.
63→type IntentsService struct{ client *Client }
64→
65→// ApprovalsService provides access to approval endpoints.
66→// TODO: implement List, Get, Approve, Deny, Modify.
67→type ApprovalsService struct{ client *Client }
68→
69→// PoliciesService provides access to policy endpoints.
70→// TODO: implement Create, Get, List, Update, Simulate.
71→type PoliciesService struct{ client *Client }
