// Package connector defines the SPI for execution connectors.
//
// A connector bridges the control plane to an external system — a payment
// processor, a git provider, a calendar service, etc. When the policy engine
// allows an action (or a human approves it), the control plane selects the
// appropriate connector and calls Execute.
//
// Each connector implementation is responsible for one external system.
// The SPI is intentionally narrow: connectors receive a bounded execution
// request and return a result. Credential injection and parameter bounding
// happen in the control plane before the connector is called.
package connector

import (
	"context"
	"sync"
)

// Connector executes an approved action against an external system.
type Connector interface {
	// Type returns the connector type identifier (e.g. "payments", "git",
	// "calendar"). Used by the registry to route execution requests.
	Type() string

	// Provider returns the specific provider name (e.g. "stripe", "github",
	// "google_calendar"). Multiple connectors may share a Type.
	Provider() string

	// Execute runs the action described by the request.
	Execute(ctx context.Context, req ExecutionRequest) (ExecutionResult, error)
}

// ExecutionRequest is passed to a connector when executing an approved action.
type ExecutionRequest struct {
	GrantID     string
	IntentID    string
	ConnectorID string
	// ActionType is the dot-namespaced action, e.g. "payment.charge".
	ActionType string
	// Parameters are the bounded, approved parameters for execution.
	// These are constrained by the execution grant and may differ from
	// the original intent if a human modified them during approval.
	Parameters map[string]any
	// Credential is the injected secret for this connector, resolved from
	// the vault. Connectors must not store or log this value.
	Credential *InjectedCredential
}

// InjectedCredential carries a resolved secret for use during execution.
// Connectors receive this transiently and must not persist it.
type InjectedCredential struct {
	Type  string
	Value []byte
}

// ExecutionResult is returned by a connector after execution.
type ExecutionResult struct {
	Status     ExecutionStatus
	Output     map[string]any
	ReceiptRef string
	Error      string
}

// ExecutionStatus is the outcome of a connector execution.
type ExecutionStatus string

const (
	ExecutionStatusSucceeded ExecutionStatus = "succeeded"
	ExecutionStatusFailed    ExecutionStatus = "failed"
	ExecutionStatusCancelled ExecutionStatus = "cancelled"
)

// Registry holds the registered connectors and routes execution requests.
// It is safe for concurrent use.
type Registry struct {
	mu         sync.RWMutex
	connectors map[string]Connector
}

// NewRegistry returns an empty connector registry.
func NewRegistry() *Registry {
	return &Registry{connectors: make(map[string]Connector)}
}

// Register adds a connector to the registry.
// The key is "<type>/<provider>", e.g. "payments/stripe".
func (r *Registry) Register(ctx context.Context, c Connector) {
	_ = ctx // available for future database-backed implementations
	key := c.Type() + "/" + c.Provider()
	r.mu.Lock()
	r.connectors[key] = c
	r.mu.Unlock()
}

// Get returns the connector for the given type and provider.
func (r *Registry) Get(ctx context.Context, connectorType, provider string) (Connector, bool) {
	_ = ctx // available for future database-backed implementations
	r.mu.RLock()
	c, ok := r.connectors[connectorType+"/"+provider]
	r.mu.RUnlock()
	return c, ok
}

// Package github implements the git connector for GitHub.
//
// This connector executes git.pull_request.* and git.commit.* actions via
// the GitHub REST API. Credentials (personal access token or GitHub App
// installation token) are injected at execution time from the vault.
package github

import (
	"context"
	"errors"

	"github.com/ALRubinger/aileron/core/connector"
)

const (
	connectorType     = "git"
	connectorProvider = "github"
)

// Connector executes git actions via GitHub.
type Connector struct{}

// New returns a new GitHub connector.
func New() *Connector {
	return &Connector{}
}

// Type implements connector.Connector.
func (c *Connector) Type() string { return connectorType }

// Provider implements connector.Connector.
func (c *Connector) Provider() string { return connectorProvider }

// Execute implements connector.Connector.
func (c *Connector) Execute(ctx context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
	if req.Credential == nil {
		return connector.ExecutionResult{}, errors.New("github: no credential injected")
	}

	switch req.ActionType {
	case "git.pull_request.create":
		return c.createPullRequest(ctx, req)
	case "git.pull_request.merge":
		return c.mergePullRequest(ctx, req)
	case "git.pull_request.close":
		return c.closePullRequest(ctx, req)
	default:
		return connector.ExecutionResult{
			Status: connector.ExecutionStatusFailed,
			Error:  "github: unsupported action type: " + req.ActionType,
		}, nil
	}
}

func (c *Connector) createPullRequest(_ context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
	// TODO: implement via GitHub REST API POST /repos/{owner}/{repo}/pulls.
	// Steps:
	//   1. Parse owner/repo from req.Parameters["repository"].
	//   2. POST pull request with head/base branch, title, body, labels.
	//   3. Return the PR URL as ReceiptRef.
	_ = req
	return connector.ExecutionResult{}, errors.New("github: createPullRequest not yet implemented")
}

func (c *Connector) mergePullRequest(_ context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
	// TODO: implement via GitHub REST API PUT /repos/{owner}/{repo}/pulls/{pull_number}/merge.
	_ = req
	return connector.ExecutionResult{}, errors.New("github: mergePullRequest not yet implemented")
}

func (c *Connector) closePullRequest(_ context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
	// TODO: implement via GitHub REST API PATCH /repos/{owner}/{repo}/pulls/{pull_number}.
	_ = req
	return connector.ExecutionResult{}, errors.New("github: closePullRequest not yet implemented")
}

// Package model defines shared domain types used across the control plane.
//
// These types are the canonical Go representations of the structures defined
// in the OpenAPI specification. All SPI packages import from here rather than
// defining their own copies.
package model

import "time"

// ActorRef identifies who or what performed an action.
type ActorRef struct {
	ID          string
	Type        ActorType
	DisplayName string
}

// ActorType classifies the actor.
type ActorType string

const (
	ActorTypeAgent            ActorType = "agent"
	ActorTypeHuman            ActorType = "human"
	ActorTypeService          ActorType = "service"
	ActorTypeConnectorRuntime ActorType = "connector_runtime"
)

// ActionTarget describes the resource an action operates on.
type ActionTarget struct {
	Kind        string
	ID          string
	DisplayName string
}

// ActionIntent describes what an agent intends to do.
type ActionIntent struct {
	// Type is a dot-namespaced action identifier, e.g. "payment.charge",
	// "git.pull_request.create", "calendar.event.create".
	Type          string
	Summary       string
	Justification string
	Target        ActionTarget
	Domain        DomainAction
	Metadata      map[string]any
}

// DomainAction carries action-type-specific fields.
// Exactly one field should be populated, corresponding to the ActionIntent.Type prefix.
type DomainAction struct {
	Git         *GitAction
	Deploy      *DeployAction
	Cloud       *CloudAction
	Email       *EmailAction
	Calendar    *CalendarAction
	Payment     *PaymentAction
	Procurement *ProcurementAction
}

// Money represents an amount in minor units (e.g. cents) with a currency code.
type Money struct {
	Amount   int64
	Currency string // ISO 4217, e.g. "USD"
}

// GitAction carries git/source-control-specific intent fields.
type GitAction struct {
	Provider       string // "github", "gitlab", "bitbucket", "custom"
	Repository     string
	Branch         string
	BaseBranch     string
	CommitSHAs     []string
	FilesChanged   []string
	PRTitle        string
	PRBody         string
	Labels         []string
	Reviewers      []string
	ChecksRequired []string
}

// DeployAction carries deployment-specific intent fields.
type DeployAction struct {
	Provider            string // "kubernetes", "vercel", "netlify", etc.
	Service             string
	Environment         string
	ArtifactRef         string
	ImageRef            string
	Cluster             string
	Namespace           string
	Strategy            string // "rolling", "blue_green", "canary", "replace", "custom"
	RollbackSupported   bool
	ChangeTicketID      string
	MaintenanceWindowID string
}

// CloudAction carries cloud-resource-specific intent fields.
type CloudAction struct {
	Provider      string // "aws", "gcp", "azure", "cloudflare", "custom"
	AccountID     string
	Region        string
	ResourceType  string
	ResourceID    string
	Operation     string
	EstimatedCost *Money
	Tags          map[string]string
}

// EmailAction carries email-specific intent fields.
type EmailAction struct {
	From        *Recipient
	To          []Recipient
	CC          []Recipient
	BCC         []Recipient
	Subject     string
	BodyText    string
	BodyHTML    string
	Attachments []AttachmentRef
	ThreadRef   string
	SendMode    string // "send_now", "draft_only"
}

// Recipient identifies an email participant.
type Recipient struct {
	Name  string
	Email string
}

// AttachmentRef references a file attachment.
type AttachmentRef struct {
	Name       string
	MIMEType   string
	URL        string
	StorageRef string
}

// CalendarAction carries calendar-specific intent fields.
type CalendarAction struct {
	Provider       string // "google_calendar", "outlook", "custom"
	Title          string
	Description    string
	Attendees      []CalendarAttendee
	StartTime      *time.Time
	EndTime        *time.Time
	Timezone       string
	Location       string
	ConferenceType string // "none", "google_meet", "zoom", "teams", "custom"
	CalendarID     string
	Visibility     string // "default", "public", "private"
}

// CalendarAttendee is a participant in a calendar event.
type CalendarAttendee struct {
	Name     string
	Email    string
	Optional bool
}

// PaymentAction carries payment-specific intent fields.
type PaymentAction struct {
	VendorName                   string
	VendorID                     string
	Amount                       Money
	MerchantCategory             string
