}

func (s *ExecutionsService) Get(ctx context.Context, executionID string) (*Execution, error) {
	var result Execution
	if err := s.client.do(ctx, http.MethodGet, "/v1/executions/"+executionID, nil, &result); err != nil {
		return nil, err
	}
	return &result, nil
}

